USERLEN = []
LONGUSER = []
def download_longmit_datasets(dataset_name: str, save_dir: str):
    qa_pairs = []
    dataset = load_dataset(dataset_name, split='train', trust_remote_code=True, streaming=True)
    for i, d in enumerate(dataset):
        # if i > 400: break
        all_docs = d['all_docs']
        if d['type'] in ['inter_doc', 'intra_doc']:
            if d['language'] == 'en':
                content_key = 'Passage {pi}:\n'
                # with CoT
                instruction_format = 'Answer the question based on the given passages.\n\nThe following are given passages.\n{concat_content}\n\nAnswer the question based on the given passages and provide a complete reasoning process.\nQuestion:{q}'
            else:
                content_key = '文章 {pi}：\n'
                # with CoT
                instruction_format = '根据给定的段落回答问题。\n\n以下是给定的段落。\n{concat_content}\n\n请结合上面材料回答以下问题，并且给出完整的推理过程。\n问题：{q}'
        else:
            if d['language'] == 'en':
                content_key = 'Passage {pi}:\n'
                instruction_format = 'Answer the question based on the given passages. Only give me the answer and do not output any other words.\n\nThe following are given passages.\n{concat_content}\n\nAnswer the question based on the given passages. Only give me the answer and do not output any other words.\nQuestion:{q}'
            else:
                content_key = '文章 {pi}：\n'
                instruction_format = '根据给定的段落回答问题。只给答案，不要输出任何其他单词。\n\n以下是给定的段落。\n{concat_content}\n\n请结合上面材料回答以下问题。只给答案，不要输出任何其他单词。\n问题：{q}'
        concat_content = '\n'.join([content_key.format(pi=di+1)+doc['content'] for di, doc in enumerate(all_docs)])
        question =  d['question']
        answer = d['answer']
        user_prompt = instruction_format.format(concat_content=concat_content, q=question)
        user_length = len(tknz2(user_prompt).input_ids)
        if user_length > 32600:
            LONGUSER.append(user_length)
            continue
        else:
            USERLEN.append(user_length)
        qa_pairs.append(json.dumps(
            {
                'language': d['language'],
                'dialogs': [
                {
                    'role': 'user',
                    'content': user_prompt,
                },
                {
                    'role': 'assistant',
                    'content': answer,
                },
                ]
            },
            ensure_ascii=False
        )+'\n')
    if not os.path.exists(save_dir):
        os.makedirs(save_dir)
    with open(os.path.join(save_dir, 'train.jsonl'), 'w') as fw:
        fw.write(''.join(qa_pairs))
